INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a72c7991-9fa4-491b-bc84-7dfda0c782ab',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery — Why It's a Warehouse, Not a Database (OLAP vs OLTP Under the Hood)$escape$,
  $escape$BigQuery is built on Google's Dremel engine using Capacitor columnar storage — not a row-oriented OLTP database. Each column is stored and compressed independently across Colossus (Google's distributed filesystem). When you run `SELECT price, quantity FROM orders`, BigQuery reads only those two columns. In PostgreSQL, the same query reads entire row pages. This is the core OLAP advantage.

Because on-demand pricing bills by bytes scanned, columnar pruning is also a cost lever. `SELECT *` on a 1 TB table scans 1 TB. Selecting 2 of 50 columns might scan 40 GB.

Clustering extends this further. `CLUSTER BY category` co-locates rows sharing the same value into contiguous storage blocks. A `WHERE category = 'Electronics'` filter then reads block-level min/max metadata and skips irrelevant blocks entirely — this is called block pruning. Partition pruning works at a coarser level via `_PARTITIONTIME` or a `DATE` column.

BigQuery rewards wide, denormalized schemas with partitioning and clustering. Normalized OLTP schemas with many joins and small lookups fight the grain of columnar execution — JOIN spills to shuffle, slot utilization spikes, and costs balloon. Design for analytical access patterns from day one.$escape$,
  $escape$-- Create a partition + cluster table optimized for OLAP scans
CREATE OR REPLACE TABLE `project.dataset.orders`
PARTITION BY DATE(created_at)
CLUSTER BY customer_id, status
AS SELECT * FROM `project.dataset.orders_raw`;

-- BigQuery performs partition pruning + block pruning automatically
SELECT
  customer_id,
  SUM(total_amount) AS revenue
FROM `project.dataset.orders`
WHERE DATE(created_at) BETWEEN '2024-01-01' AND '2024-03-31'
  AND status = 'completed'
GROUP BY customer_id;

-- Estimate bytes scanned before committing (dry run):
-- bq query --dry_run --use_legacy_sql=false 'SELECT ...'$escape$,
