INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4686fd9b-b55a-4170-8038-efa6eb8c3ee1',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery Cost Control — Slots, Partitions, and Clustering Done Right$escape$,
  $escape$BigQuery's serverless model bills on bytes scanned, not compute time — so query design directly drives your invoice. On-demand pricing charges ~$6.25/TB scanned; flat-rate slot reservations (via BigQuery Reservations API) make sense above ~100TB/month by giving predictable capacity through FLEX, STANDARD, or ENTERPRISE commitments assigned to projects via reservation assignments.

Partitioning and clustering are your first line of defense. Partition on a DATE/TIMESTAMP column (or an integer range) so the query engine can prune entire storage blocks before scanning. Clustering on up to 4 columns within each partition lets BigQuery skip blocks based on column min/max metadata — most effective on high-cardinality filter columns like user_id or event_type.

Always filter on the partition column before joining or aggregating; a missing partition filter forces a full table scan regardless of clustering. Use INFORMATION_SCHEMA.PARTITIONS to audit partition pruning efficiency, and the Jobs API (jobs.get → statistics.query.totalBytesProcessed vs. totalBytesBilled) to verify savings. Enable require_partition_filter at the table level to enforce pruning across all queries.$escape$,
  $escape$-- Enforce partition pruning + clustering savings
CREATE OR REPLACE TABLE analytics.events
PARTITION BY DATE(occurred_at)
CLUSTER BY user_id, event_type
OPTIONS (require_partition_filter = TRUE)
AS SELECT * FROM staging.raw_events WHERE FALSE;

-- Verify bytes scanned vs billed for a query job
SELECT
  job_id,
  total_bytes_processed / pow(1024,4) AS tb_processed,
  total_bytes_billed   / pow(1024,4) AS tb_billed
FROM `region-us`.INFORMATION_SCHEMA.JOBS_BY_PROJECT
WHERE creation_time > TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 1 DAY)
ORDER BY tb_billed DESC
LIMIT 20;$escape$,
