INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '588dddd8-ed5c-4279-8692-0ddb4e870aaf',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery vs Redshift — Distribution Keys, Sort Keys, VACUUM, and What BigQuery Abstracts Away$escape$,
  $escape$BigQuery handles what Redshift forces you to manage manually. In Redshift, you must define a DISTKEY (hash, even, or all) to control how rows are spread across nodes — poor choices cause data skew and slow joins. SORTKEY (compound or interleaved) determines on-disk ordering for range scans. After bulk loads or deletes, you must run VACUUM to reclaim space and re-sort rows, then ANALYZE to refresh statistics. RA3 nodes decouple compute from storage using Redshift Managed Storage (RMS), so you scale them independently — but you still own the tuning.

BigQuery does none of this. Colossus handles distributed storage automatically; Dremel parallelizes execution across slots without node-level placement decisions. The closest BigQuery primitive is CLUSTER BY, which sorts data within partitions for pruning — no manual VACUUM, no ANALYZE, no distribution strategy. Capacitor columnar encoding and automatic stats collection happen server-side. If you're evaluating Redshift or reading someone else's DDL, knowing this mapping prevents you from searching for BigQuery equivalents that simply don't exist.$escape$,
  $escape$-- Redshift: manual distribution + sort key + maintenance required
CREATE TABLE orders (
  order_id BIGINT,
  customer_id BIGINT,
  created_at TIMESTAMP,
  amount NUMERIC(10,2)
)
DISTKEY(customer_id)
SORTKEY(created_at);

VACUUM orders TO 95 PERCENT;
ANALYZE orders;

-- BigQuery equivalent: partitioning + clustering, no VACUUM/ANALYZE
CREATE TABLE `project.dataset.orders`
PARTITION BY DATE(created_at)
CLUSTER BY customer_id AS
SELECT * FROM source;$escape$,
