INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7905b028-7a2f-4c78-8907-d534715f4fb5',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery to Databricks — Delta Lake, Unity Catalog, and Photon Through a BigQuery Lens$escape$,
  $escape$BigQuery users moving to Databricks face a lakehouse paradigm shift: storage (Delta Lake on object storage) and compute (Spark clusters) are decoupled — there's no serverless slot abstraction managing this invisibly for you. Delta Lake replaces BigQuery's native Capacitor format. It brings ACID transactions and time travel via `VERSION AS OF` / `TIMESTAMP AS OF`, directly analogous to BigQuery's `FOR SYSTEM_TIME AS OF`. Data skipping uses Z-ordering (`OPTIMIZE ... ZORDER BY`) — BigQuery handles equivalent pruning automatically via clustering columns. Unity Catalog maps to BigQuery's project → dataset → table hierarchy as catalog → schema → table, but adds column-level masking policies and row filters that BigQuery implements via column-level security and authorized views. The Photon engine is Databricks' Dremel counterpart — a vectorized C++ runtime accelerating SQL and DataFrame workloads with no code changes required. The critical operational gap: BigQuery's autoscaling and automatic table maintenance are your problem in Databricks. You must size clusters, run `OPTIMIZE` for file compaction, and schedule `VACUUM` to expire stale snapshots — none of this is managed for you.$escape$,
  $escape$-- BigQuery: FOR SYSTEM_TIME AS OF '2024-01-01'
-- Databricks Delta Lake equivalent:
SELECT * FROM sales_delta VERSION AS OF 42;
SELECT * FROM sales_delta TIMESTAMP AS OF '2024-01-01T00:00:00';

-- BigQuery clustering → Delta Z-ordering (manual, not automatic)
OPTIMIZE sales_delta
  ZORDER BY (customer_id, event_date);

-- BigQuery automatic expiry → explicit VACUUM in Delta
VACUUM sales_delta RETAIN 168 HOURS;

-- Unity Catalog: catalog.schema.table (vs BQ project.dataset.table)
SELECT * FROM prod_catalog.sales_schema.transactions
WHERE region = 'US';$escape$,
