INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8efbba10-7d80-46df-ad35-367b307636c0',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery Data Modeling — Why Wide Tables Beat Star Schemas$escape$,
  $escape$BigQuery's columnar storage changes the calculus on dimensional modeling. Star and snowflake schemas made sense for row-based OLTP engines where normalization reduced storage. In BigQuery, JOINs cause shuffle across distributed slots, and on-demand billing charges per bytes scanned — not per row or join. Wide, denormalized tables eliminate that overhead entirely.

Instead of a classic snowflake (orders → customers → segments → regions), flatten dimensions into the fact table using BigQuery's native STRUCT and ARRAY types. Nested fields are co-located on disk, so customer.region costs nothing extra alongside order_id — and column pruning means you only scan what you SELECT.

Combine PARTITION BY DATE(order_date) with CLUSTER BY on your most-filtered dimensions (region, product_category). This gives you dimension-key lookups without maintaining a separate dimension table or surrogate key index.

Reserve separate dimension tables only when multiple fact tables share the same dimension and you need a single update path — then use BigQuery materialized views to pre-join them back for query performance. Avoid snowflake schemas entirely; each normalization level adds a shuffle join that burns slots and inflates latency.$escape$,
  $escape$CREATE TABLE `project.dataset.orders_wide`
PARTITION BY DATE(order_date)
CLUSTER BY region, product_category
AS
SELECT
  o.order_id,
  o.order_date,
  o.revenue,
  STRUCT(c.customer_id, c.segment, c.region) AS customer,
  STRUCT(p.product_id, p.category AS product_category, p.brand) AS product
FROM `raw.orders` o
JOIN `raw.customers` c USING (customer_id)
JOIN `raw.products` p USING (product_id);$escape$,
