INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9ad656d8-e269-41b6-bb37-3867d54076e4',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery ELT — Why You Load Raw, Transform Later, and Let dbt Own the Logic$escape$,
  $escape$Traditional ETL transforms data before loading — a relic of when compute was expensive and storage was scarce. BigQuery inverts this. With columnar storage, automatic clustering, and serverless query execution priced per byte scanned, it's cheaper and faster to load raw data into a dedicated dataset (e.g., `raw.ga4_events`) and transform it inside BigQuery using SQL.

dbt slots in as the transformation layer: it compiles `.sql` model files into `CREATE OR REPLACE TABLE` / `CREATE OR REPLACE VIEW` statements that run directly against BigQuery, manages a DAG of dependencies, and handles incremental materializations via `__dbt_tmp` staging tables. You get version-controlled, testable SQL instead of fragile pipeline scripts.

The key BigQuery-specific win: dbt incremental models use `MERGE` statements with `unique_key`, which maps to BigQuery's native DML. Combine this with partitioned tables on `event_date` and `require_partition_filter = true`, and you scan only the partitions dbt touches — keeping costs predictable as data volumes grow.$escape$,
  $escape$-- models/marts/fct_ga4_sessions.sql
{{ config(
    materialized='incremental',
    unique_key='session_id',
    partition_by={'field': 'event_date', 'data_type': 'date'},
    cluster_by=['user_pseudo_id']
) }}

SELECT
    (SELECT value.int_value FROM UNNEST(event_params) WHERE key = 'ga_session_id') AS session_id,
    user_pseudo_id,
    DATE(TIMESTAMP_MICROS(event_timestamp)) AS event_date,
    COUNT(*) AS event_count
FROM {{ source('raw', 'ga4_events') }}
{% if is_incremental() %}
    WHERE DATE(TIMESTAMP_MICROS(event_timestamp)) >= DATE_SUB(CURRENT_DATE(), INTERVAL 3 DAY)
{% endif %}
GROUP BY 1, 2, 3$escape$,
  $escape$sql$escape$,
