INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '599b2b12-faa3-406a-8163-47c9321b7bfd',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery Cost Management — Estimate Costs, Control Slots, and Cache with Materialized Views$escape$,
  $escape$Every BigQuery query on on-demand pricing costs $6.25/TB processed. Before running expensive queries, use INFORMATION_SCHEMA.JOBS or dry-run execution to estimate bytes billed. Set `dry_run: true` in the job config — BigQuery validates the query and returns `totalBytesProcessed` without executing or charging. For capacity-based pricing, monitor slot utilization via INFORMATION_SCHEMA.JOBS_BY_PROJECT: high slot contention means queries queue rather than fail, but latency spikes. Use `reservation_id` to isolate workloads. Materialized views are BigQuery's most underused cost lever — they pre-aggregate query results and are automatically used by the query optimizer (smart tuning) even if you don't reference them directly. A materialized view refreshes incrementally on base table DML, not full scans. Pair them with partition filters on the base table to cut refresh cost. For dashboards hitting the same aggregation repeatedly, a materialized view can drop per-query cost from hundreds of GBs to near zero.$escape$,
  $escape$-- Dry-run via bq CLI to estimate bytes before execution
-- bq query --dry_run 'SELECT user_id, SUM(spend) FROM `project.dataset.orders` WHERE DATE(created_at) = "2024-01-01" GROUP BY 1'

-- Check last 7 days slot usage and bytes billed per user
SELECT
  user_email,
  SUM(total_bytes_billed) / POW(1024, 4) AS tb_billed,
  SUM(total_slot_ms) / 1000 AS slot_seconds
FROM `region-us`.INFORMATION_SCHEMA.JOBS_BY_PROJECT
WHERE DATE(creation_time) >= DATE_SUB(CURRENT_DATE(), INTERVAL 7 DAY)
  AND job_type = 'QUERY'
GROUP BY 1
ORDER BY tb_billed DESC
LIMIT 20;$escape$,
  $escape$sql$escape$,
