INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '174a21f8-f544-4bab-899d-b1cadc0e9a84',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery Data Quality — Nulls, Deduplication, and Constraint Enforcement$escape$,
  $escape$BigQuery has no enforced PRIMARY KEY or UNIQUE constraints — they're declared as hints for the query optimizer, not guardrails. That means data quality is your responsibility at write time. For null handling, use COALESCE and IFNULL in your transformation layer, but lean on column-level NOT NULL mode in your schema definitions to reject bad rows at load time via the Storage Write API. For deduplication, the canonical pattern is a MERGE with a CTE that windows over your source using ROW_NUMBER() OVER (PARTITION BY id ORDER BY updated_at DESC), keeping only rank=1 rows before merging into the target table. Avoid SELECT DISTINCT on large tables — it forces a full shuffle. For constraint simulation, use information_schema.TABLE_CONSTRAINTS to document intent and combine with scheduled queries that assert COUNT(*) = COUNT(DISTINCT id), alerting via BigQuery scheduled query notifications or Dataplex data quality rules, which support row-level checks with SQL predicates and integrate with Cloud Logging for drift alerts.$escape$,
  $escape$-- Idempotent dedup MERGE for BigQuery
MERGE `project.dataset.orders` AS target
USING (
  SELECT * EXCEPT(rn)
  FROM (
    SELECT *,
      ROW_NUMBER() OVER (PARTITION BY order_id ORDER BY updated_at DESC) AS rn
    FROM `project.dataset.orders_staging`
  )
  WHERE rn = 1
) AS source
ON target.order_id = source.order_id
WHEN MATCHED THEN UPDATE SET target.updated_at = source.updated_at, target.status = source.status
WHEN NOT MATCHED THEN INSERT ROW;$escape$,
  $escape$sql$escape$,
