INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2029d9c4-6163-42d9-ab84-5dfb3a9ebb70',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery Performance Optimization — Caching, Materialized Views, and Slot Efficiency$escape$,
  $escape$BigQuery's query result cache is automatic but often misunderstood. Results are cached for 24 hours per project, but only if the query is identical (byte-for-byte), references no non-deterministic functions like CURRENT_TIMESTAMP(), and the underlying tables haven't changed. Use this to your advantage in dashboards by parameterizing carefully.

For repeated aggregations over large partitioned tables, materialized views are the real win. BigQuery auto-refreshes them on DML changes and can serve dashboard queries directly from the materialized result — zero full-scan cost. Define them with a PARTITION BY clause that mirrors the base table to keep refresh incremental.

On the query side, always filter on partition columns first — BigQuery's partition pruning is aggressive but only fires on WHERE clauses referencing the partition column directly. Avoid wrapping partition columns in functions (DATE(ts) kills pruning; use ts BETWEEN instead). Use APPROX_COUNT_DISTINCT() over COUNT(DISTINCT) for analytics at scale — it's 40–50x faster with <1% error. For slot-heavy joins, place the larger table on the left side of JOIN to guide the distributed shuffle.$escape$,
  $escape$-- Materialized view with incremental refresh via partitioning
CREATE MATERIALIZED VIEW analytics.daily_event_counts
PARTITION BY event_date
CLUSTER BY event_type
OPTIONS (enable_refresh = true, refresh_interval_minutes = 60)
AS
SELECT
  DATE(created_at) AS event_date,
  event_type,
  APPROX_COUNT_DISTINCT(user_id) AS approx_unique_users,
  COUNT(*) AS total_events
FROM raw.events
WHERE created_at >= '2024-01-01'
GROUP BY 1, 2;$escape$,
