INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2309e3ee-dc43-4317-8757-72ae18491860',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery Data Sharing — Authorized Views, Cross-Account IAM, and Analytics Hub$escape$,
  $escape$BigQuery data sharing operates at three distinct tiers. Direct dataset sharing — grant `roles/bigquery.dataViewer` to a principal in another project and they can read every table in that dataset. For row or column filtering without exposing base tables, use authorized views: create the view in a separate dataset, register it as an authorized view on the source dataset via `bq update --add_view_access_policies`, and callers only see the view's output while the view itself queries the protected tables with elevated access — no base table IAM required for the consumer.

For cross-organization sharing at scale, Analytics Hub eliminates manual IAM sprawl. Publishers create a Data Exchange, attach Listings to source datasets, and subscribers link them — producing a read-only linked dataset inside the subscriber's own project. No data is copied; queries run against publisher storage and billing falls on the subscriber's project. Row access policies defined on the publisher's dataset propagate automatically to linked datasets.

Combine authorized views with `SESSION_USER()` for per-identity row filtering. For bulk policy propagation across many views, add an authorized dataset at the dataset level rather than registering each view individually.$escape$,
  $escape$-- 1. Secure view with per-identity row filtering
CREATE OR REPLACE VIEW `proj.public_views.orders_summary` AS
SELECT order_id, customer_id, total_usd, region
FROM `proj.private_data.orders`
WHERE region IN (
  SELECT allowed_region
  FROM `proj.private_data.user_acl`
  WHERE user_email = SESSION_USER()
);

-- 2. Register the view as authorized on the source dataset (run in shell)
-- bq update \
--   --add_view_access_policies '[{"projectId":"proj","datasetId":"public_views","tableId":"orders_summary"}]' \
--   proj:private_data$escape$,
