INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4dfd8ae0-7615-46cd-a2e5-3ba8e141ffe8',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery Incremental Loading — Append, Upsert, and MERGE Patterns$escape$,
  $escape$BigQuery's append-only model is the cheapest path: stream or batch-load new rows into a partitioned table, query with a `WHERE _PARTITIONTIME >= TIMESTAMP_SUB(...)` filter, and pay nothing for writes. It breaks the moment rows need to change.

For mutable sources, use the MERGE statement against a staging table. Load deltas into a temp/staging table (partitioned by `ingestion_time`), then MERGE into the target on your natural key. BigQuery MERGE scans full target partitions unless you add a `WHEN MATCHED AND target.updated_at < source.updated_at` guard and cluster on the merge key—without this, costs balloon on large tables.

For CDC (Debezium, Datastream), the canonical pattern is append raw change events (op: I/U/D, `_change_sequence`) into a raw layer, then materialize the latest state with a `ROW_NUMBER() OVER (PARTITION BY id ORDER BY _change_sequence DESC)` window query into a clean layer. This avoids MERGE entirely on the raw tier and keeps full audit history. Scheduled queries or dbt incremental models (`unique_key` + `merge` strategy) automate the final materialization step.$escape$,
  $escape$-- Upsert via MERGE with partition pruning
MERGE `project.dataset.orders` T
USING (
  SELECT * FROM `project.dataset.orders_staging`
  WHERE DATE(ingestion_time) = CURRENT_DATE()
) S
ON T.order_id = S.order_id
  AND T.created_date >= DATE_SUB(CURRENT_DATE(), INTERVAL 7 DAY) -- partition filter
WHEN MATCHED AND T.updated_at < S.updated_at THEN
  UPDATE SET T.status = S.status, T.updated_at = S.updated_at
WHEN NOT MATCHED THEN
  INSERT (order_id, status, created_date, updated_at)
  VALUES (S.order_id, S.status, S.created_date, S.updated_at);$escape$,
  $escape$sql$escape$,
