INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c5c27464-0b40-448d-b96c-f25b60ee5f85',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery Monitoring — Query History, Cost Dashboards, and Slow Query Alerts$escape$,
  $escape$BigQuery's `INFORMATION_SCHEMA.JOBS` view is your primary observability surface. It exposes every job executed in your project — including bytes billed, slot milliseconds consumed, query text, and wall-clock duration. Querying it lets you build cost dashboards without any third-party tooling.

For cost tracking, aggregate `total_bytes_billed` grouped by `user_email` or `labels.key` to attribute spend. A single on-demand query billing 5 TB at $6.25/TB shows up immediately.

For slow query alerts, filter on `TIMESTAMP_DIFF(end_time, start_time, SECOND) > 60` and join with `total_slot_ms` to distinguish long-running queries from slot-starved ones — the fix is different for each.

To catch regressions automatically, schedule a BigQuery scheduled query that writes aggregated job stats to a summary table daily. Then connect Looker Studio or Grafana (via the BigQuery connector) for live dashboards. For real-time alerting, route `cloudaudit.googleapis.com/data_access` logs from Cloud Logging to Pub/Sub and trigger a Cloud Function when `jobStatistics.totalBilledBytes` exceeds your threshold.$escape$,
  $escape$-- Top 10 most expensive queries in the last 7 days
SELECT
  job_id,
  user_email,
  ROUND(total_bytes_billed / POW(1024, 4), 4) AS tb_billed,
  ROUND(total_bytes_billed / POW(1024, 4) * 6.25, 2) AS est_cost_usd,
  TIMESTAMP_DIFF(end_time, start_time, SECOND) AS duration_sec,
  total_slot_ms,
  SUBSTR(query, 1, 120) AS query_preview
FROM `region-us`.INFORMATION_SCHEMA.JOBS
WHERE creation_time >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 7 DAY)
  AND job_type = 'QUERY'
  AND state = 'DONE'
  AND error_result IS NULL
ORDER BY total_bytes_billed DESC
LIMIT 10;$escape$,
