INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd88db375-19de-4132-9fa9-417b3c5475ab',
  '00000000-0000-0000-0000-000000000001',
  $escape$BigQuery Integration — Wiring dbt, Airflow, Looker, and Reverse ETL Into One Coherent Stack$escape$,
  $escape$BigQuery sits at the center of most modern data stacks, but the integration surface is where teams lose hours. With dbt, point your profiles.yml at BigQuery using the bigquery adapter — use oauth or service_account auth, set location explicitly (US vs EU matters for cross-region joins), and lean on dbt's built-in incremental strategy using _partitiontime for partitioned tables. For Airflow, skip the generic PythonOperator and use BigQueryInsertJobOperator from apache-airflow-providers-google — it submits jobs asynchronously and polls via the Jobs API, so you're not blocking a worker slot. BI tools like Looker use BigQuery's INFORMATION_SCHEMA.TABLES and column-level caching — enable BI Engine reservation on your dataset to get sub-second cached results without rewriting queries. For reverse ETL (Census, Hightouch), grant the service account bigquery.dataViewer on source datasets and bigquery.jobUser at the project level — never project-wide editor. Use authorized views to expose transformed models without granting raw table access to third-party connectors.$escape$,
  $escape$# dbt profiles.yml — BigQuery service account config
my_project:
  target: prod
  outputs:
    prod:
      type: bigquery
      method: service-account
      project: my-gcp-project
      dataset: analytics
      location: US
      keyfile: /secrets/sa-key.json
      threads: 8
      timeout_seconds: 300
      priority: interactive
      retries: 2$escape$,
  $escape$bash$escape$,
